<?php if(!defined('ABSPATH')){exit;}function lef_get_otp_verify_email_html($data){$otp_code=isset($data['otp_code'])?$data['otp_code']:'000000';$user_name=isset($data['user_name'])?$data['user_name']:'User';$expires_in=isset($data['expires_in'])?$data['expires_in']:'60 seconds';
$primary_color='#F15E74';$bg_color='#F4F7F9';ob_start(); ?><!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><style>body{font-family:'Helvetica Neue',Helvetica,Arial,sans-serif;background-color:<?php echo $bg_color; ?>; margin: 0; padding: 40px 20px; color: #1A1A1A; } .container { max-width: 540px; margin: 0 auto; background: #ffffff; border-radius: 24px; overflow: hidden; box-shadow: 0 10px 30px rgba(0,0,0,0.08); } .header { background-color:<?php echo $primary_color; ?>; padding: 30px 20px; text-align: center; } .header h1 { color: #ffffff; margin: 0; font-size: 26px; font-weight: 600; letter-spacing: 2px; text-transform: uppercase; } .content { padding: 20px; text-align: center; } .title { font-size: 24px; font-weight: 600; color: #000000; margin: 0 0 20px 0; } .text { font-size: 16px; line-height: 1.6; color: #4B5563; margin-bottom: 30px; font-weight: 500; } .otp-box { background: #FFF1F2; border: 2px solid<?php echo $primary_color; ?>; border-radius: 16px; padding: 24px; margin: 0 auto 30px; display: inline-block; min-width: 200px; } .otp-code { font-size: 36px; font-weight: 800; letter-spacing: 10px; color:<?php echo $primary_color; ?>; margin: 0; } .note { color: #EA0124; font-size: 14px; font-weight: 700; line-height: 1.5; margin-top: 35px; border-top: 1px solid #E5E7EB; padding-top: 25px; } .note a { color: #2563EB; text-decoration: none; } .footer { padding: 30px; text-align: center; font-size: 14px; color: #64748B; background: #F9FAFB; font-weight: 600; } </style></head><body><div class="container"><div class="header"><h1><?php echo esc_html(get_bloginfo('name')); ?></h1></div><div class="content"><h2 class="title">Account Verification</h2><p class="text"> Hello<?php echo esc_html($user_name); ?>,<br><br> To complete your profile update, please use the following one-time password (OTP). This code will expire in <strong><?php echo esc_html($expires_in); ?></strong>. </p><div class="otp-box"><div class="otp-code"><?php echo esc_html($otp_code); ?></div></div><div class="note"> Note: If you did not request this update, please ignore this email or contact support at <a href="mailto:<?php echo esc_attr(get_option('admin_email')); ?>"><?php echo esc_html(get_option('admin_email')); ?></a>. </div></div><div class="footer"> &copy;<?php echo date('Y'); ?><?php echo esc_html(get_bloginfo('name')); ?></div></div></body></html><?php return ob_get_clean();}